SELECT s.store_id, s.image_url, s.business_name, s.store_desc, s.addr_base, s.min_headcount, s.max_headcount, s.is_Battery_supported, GROUP_CONCAT(fc.name SEPARATOR ',') as food_category_names FROM stores s INNER JOIN store_food_categories sfc ON s.store_id = sfc.store_id INNER JOIN food_categories fc ON sfc.food_category_id = fc.food_category_id INNER JOIN store_regions sr ON s.store_id = sr.store_id
AND sr.region_id = #{storeListReq.regionId}
AND s.store_id NOT IN ( SELECT r.store_id FROM reservations r WHERE #{storeListReq.date} BETWEEN DATE(r.event_start_date) AND DATE(r.event_end_date) AND r.status IN ( 'CONFIRMED', 'PAYMENT_COMPLETED', 'COMPLETED' ) )
AND s.min_headcount <= #{storeListReq.minHeadcount}
AND s.max_headcount >= #{storeListReq.maxHeadcount}
AND s.is_battery_supported = TRUE
AND fc.name IN
#{categoryName}
GROUP BY s.store_id ORDER BY s.store_id DESC LIMIT #{storeListReq.limit} OFFSET #{offset}

SELECT COUNT(DISTINCT s.store_id) FROM stores s INNER JOIN store_food_categories sfc ON s.store_id = sfc.store_id INNER JOIN food_categories fc ON sfc.food_category_id = fc.food_category_id INNER JOIN store_regions sr ON s.store_id = sr.store_id
AND sr.region_id = #{storeListReq.regionId}
AND s.store_id NOT IN ( SELECT r.store_id FROM reservations r WHERE #{storeListReq.date} BETWEEN DATE(r.event_start_date) AND DATE(r.event_end_date) AND r.status IN ( 'CONFIRMED', 'PAYMENT_COMPLETED', 'COMPLETED' ) )
AND s.min_headcount <= #{storeListReq.minHeadcount}
AND s.max_headcount >= #{storeListReq.maxHeadcount}
AND s.is_battery_supported = TRUE
AND fc.name IN
#{categoryName}
